mapper.insert:
INSERT INTO SCHEDULE
	( SCHEDULE_ID
	, PROGRAM_ID
	, EVENT_DATE
	, EVENT_TIME
	, TOTAL_SEATS
	, AVAIL_SEATS
	, STATUS
	, REG_DT )
VALUES
	( #{scheduleId}
	, #{programId}
	, #{eventDate}
	, #{eventTime}
	, #{totalSeats}
	, #{availSeats}
	, #{status}
	, NOW() )

mapper.update:
UPDATE SCHEDULE
SET PROGRAM_ID  = #{programId}
  , EVENT_DATE  = #{eventDate}
  , EVENT_TIME  = #{eventTime}
  , TOTAL_SEATS = #{totalSeats}
  , AVAIL_SEATS = #{availSeats}
  , STATUS      = #{status}
WHERE SCHEDULE_ID = #{scheduleId}

mapper.select:
SELECT S.SCHEDULE_ID , S.PROGRAM_ID , S.EVENT_DATE , S.EVENT_TIME , S.TOTAL_SEATS , S.AVAIL_SEATS , S.STATUS , S.REG_DT , P.PROGRAM_NM FROM SCHEDULE S LEFT JOIN PROGRAM P ON S.PROGRAM_ID = P.PROGRAM_ID WHERE 1=1
AND S.SCHEDULE_ID LIKE CONCAT('%', #{searchKeyword}, '%')
AND S.STATUS = #{searchKeyword}
ORDER BY S.SCHEDULE_ID ASC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT COUNT(*) totcnt FROM SCHEDULE S LEFT JOIN PROGRAM P ON S.PROGRAM_ID = P.PROGRAM_ID WHERE 1=1
AND S.SCHEDULE_ID LIKE CONCAT('%', #{searchKeyword}, '%')
AND S.STATUS = #{searchKeyword}
